package jetbrains.mps.tool.environment;

/*Generated by MPS */

import org.apache.log4j.Logger;
import org.apache.log4j.LogManager;
import jetbrains.mps.core.platform.Platform;
import org.jetbrains.annotations.NotNull;
import jetbrains.mps.core.platform.PlatformFactory;
import jetbrains.mps.core.platform.PlatformOptionsBuilder;
import jetbrains.mps.generator.GenerationSettingsProvider;
import jetbrains.mps.generator.DefaultModifiableGenerationSettings;
import jetbrains.mps.extapi.module.FacetsRegistry;
import org.jetbrains.mps.openapi.module.FacetsFacade;
import jetbrains.mps.classloading.DumbIdeaPluginFacet;
import org.jetbrains.mps.openapi.module.SModuleFacet;
import org.jetbrains.mps.openapi.module.SModule;
import org.jetbrains.annotations.Nullable;
import jetbrains.mps.library.LibraryInitializer;
import java.util.List;
import jetbrains.mps.library.contributor.LibraryContributor;
import jetbrains.mps.internal.collections.runtime.ListSequence;
import java.util.ArrayList;
import jetbrains.mps.internal.collections.runtime.SetSequence;
import jetbrains.mps.project.Project;
import java.io.File;
import jetbrains.mps.core.tool.environment.util.FileMPSProject;
import jetbrains.mps.util.FileUtil;

public final class MpsEnvironment extends EnvironmentBase {
  private static final Logger LOG = LogManager.getLogger(MpsEnvironment.class);
  private Platform myPlatform;

  static {
    EnvironmentBase.initializeLog4j();
  }

  public MpsEnvironment(@NotNull EnvironmentConfig config) {
    super(config);
  }

  public void init() {
    if (LOG.isInfoEnabled()) {
      LOG.info("Creating MPS environment");
    }
    myPlatform = PlatformFactory.initPlatform(PlatformOptionsBuilder.ALL);

    myPlatform.findComponent(GenerationSettingsProvider.class).setGenerationSettings(new DefaultModifiableGenerationSettings());
    registerFacetFactory(myPlatform.findComponent(FacetsRegistry.class));
    super.init(myPlatform);
  }

  private void registerFacetFactory(FacetsFacade facetsFacade) {
    FacetsFacade.FacetFactory dumbFactory = facetsFacade.getFacetFactory(DumbIdeaPluginFacet.FACET_TYPE);
    assert dumbFactory != null;
    facetsFacade.removeFactory(dumbFactory);
    facetsFacade.addFactory(DumbIdeaPluginFacet.FACET_TYPE, new FacetsFacade.FacetFactory() {

      @Override
      public SModuleFacet create(@NotNull SModule module) {
        DumbIdeaPluginFacet rv = new DumbIdeaPluginFacet() {
          @Override
          @Nullable
          public ClassLoader getClassLoader() {
            return getRootClassLoader();
          }
        };
        rv.setModule(module);
        return rv;
      }
    });
  }


  @Override
  protected void initLibraries(@NotNull LibraryInitializer libInitializer) {
    final List<LibraryContributor> libContribs = ListSequence.fromList(new ArrayList<LibraryContributor>());
    LibraryContributorHelper helper = new LibraryContributorHelper(myConfig, getRootClassLoader());
    if (SetSequence.fromSet(myConfig.getLibs()).isNotEmpty()) {
      ListSequence.fromList(libContribs).addElement(helper.createLibContributorForLibs());
    }
    // todo this should go away. Instead, a regular contributor for plugins should perform 
    if (myConfig.getPlugins() != null && SetSequence.fromSet(myConfig.getPlugins()).isNotEmpty()) {
      ListSequence.fromList(libContribs).addElement(helper.createLibContributorForPlugins());
    }
    libInitializer.load(libContribs);
  }

  @Override
  @NotNull
  public Project doOpenProject(@NotNull File projectFile) {
    FileMPSProject project = new FileMPSProject(projectFile, myPlatform);
    return project;
  }

  @NotNull
  @Override
  public Project createEmptyProject() {
    checkInitialized();
    if (LOG.isInfoEnabled()) {
      LOG.info("Creating an empty project");
    }
    File projectFile = FileUtil.createTmpDir();
    projectFile.deleteOnExit();
    Project project = openProject(projectFile);
    return project;
  }

  @Override
  public void doDispose() {
    myPlatform.dispose();
    myPlatform = null;
  }

  @Override
  public void flushAllEvents() {
    // do nothing 
    checkInitialized();
  }

  @Override
  public Platform getPlatform() {
    return myPlatform;
  }

}
